# WRONG: hook stores the tensor with grad history + does not remove
bad_maps = {}
def bad_hook(m, inp, out):
    bad_maps["last"] = out  # retains computation graph!
handle = model.features[0].register_forward_hook(bad_hook)
# ... forward passes accumulate graph memory
# handle never removed → hook fires on every future forward pass too

# RIGHT: detach, use context manager to guarantee cleanup
from contextlib import contextmanager

@contextmanager
def capture_feature_maps(model, layer_names):
    """Context manager that captures feature maps and cleans up automatically."""
    captured = {}
    handles = []
    for name, module in model.named_modules():
        if name in layer_names:
            def hook(m, inp, out, _name=name):
                captured[_name] = out.detach()  # .detach() is critical
            handles.append(module.register_forward_hook(hook))
    try:
        yield captured
    finally:
        for h in handles:
            h.remove()  # always runs, even if an exception occurs

# Usage:
import torch
from torchvision import models
vgg = models.vgg16(weights=None).eval()
with capture_feature_maps(vgg, {"features.0", "features.5"}) as maps:
    with torch.no_grad():
        _ = vgg(torch.randn(1, 3, 224, 224))
print({k: v.shape for k, v in maps.items()})
# {'features.0': (1, 64, 224, 224), 'features.5': (1, 128, 112, 112)}
# Hooks are removed — no memory leak
